import sys
from typing import List

class Solution:
    def maxCoins(self, coins: List[int]) -> int:
        coins.sort(reverse=True)
        max_coins = 0
        for coin in coins:
            max_coins += coin
        return max_coins


if __name__ == '__main__':
    solution = Solution()
    nums = list(map(int, input().split()))
    print(solution.maxCoins(nums))

