#include <bits/stdc++.h>

using namespace std;

class Solution {
public:
int maxCoins(vector<int> &coins) {
    sort(coins.begin(), coins.end(), greater<int>());
    int max_coins = 0;
    for (int coin : coins) {
        max_coins += coin;
    }
    return max_coins;
}
};

int main() {
    Solution sol;
    int n;
    cin >> n;
    int coins[n];
    for (int i = 0; i < n; i++) {
        cin >> coins[i];
    }
    cout << sol.maxCoins(vector<int>(coins, coins + n));
    return 0;
}
